import{_ as e,o as a,c as i,ag as o}from"./chunks/framework.BDReElpY.js";const u=JSON.parse('{"title":"Introduction to Vex","description":"","frontmatter":{},"headers":[],"relativePath":"archive/guide/00_introduction.md","filePath":"archive/guide/00_introduction.md"}'),l={name:"archive/guide/00_introduction.md"};function n(r,t,s,d,g,c){return a(),i("div",null,[...t[0]||(t[0]=[o('<h1 id="introduction-to-vex" tabindex="-1">Introduction to Vex <a class="header-anchor" href="#introduction-to-vex" aria-label="Permalink to &quot;Introduction to Vex&quot;">​</a></h1><p>Vex is <code>High-Performance Systems Programming</code> reimagined.</p><p>It is designed to solve the <strong>&quot;Three Language Problem&quot;</strong> in modern software stacks:</p><ol><li><strong>Low Level</strong>: C++/Rust for kernels and engines.</li><li><strong>Concurrency</strong>: Go/Java for networked services.</li><li><strong>High Level</strong>: Python for ML and scripting.</li></ol><p>Vex aims to be a single language that spans all three domains without compromise.</p><h2 id="core-pillars" tabindex="-1">Core Pillars <a class="header-anchor" href="#core-pillars" aria-label="Permalink to &quot;Core Pillars&quot;">​</a></h2><h3 id="_1-safety-without-the-struggle" tabindex="-1">1. Safety without the Struggle <a class="header-anchor" href="#_1-safety-without-the-struggle" aria-label="Permalink to &quot;1. Safety without the Struggle&quot;">​</a></h3><p>Vex provides memory safety (no segfaults, no data races) using a Borrow Checker, similar to Rust. However, it simplifies the model by automating &quot;smart pointer&quot; choice (VUMM) and reducing the need for explicit lifetime annotations in common code.</p><h3 id="_2-concurrency-built-in" tabindex="-1">2. Concurrency Built-In <a class="header-anchor" href="#_2-concurrency-built-in" aria-label="Permalink to &quot;2. Concurrency Built-In&quot;">​</a></h3><p>Like Go, Vex treats concurrency as a first-class citizen. Spawning a &quot;goroutine&quot; is a keyword (<code>go</code>). Channels (<code>chan</code>) are the primary way to communicate. You don&#39;t need an external library to write a scalable server.</p><h3 id="_3-silicon-native" tabindex="-1">3. Silicon Native <a class="header-anchor" href="#_3-silicon-native" aria-label="Permalink to &quot;3. Silicon Native&quot;">​</a></h3><p>Vex is the first language designed for the AI era. Vectors, matrices, and tensors are primitive types, not libraries.</p><ul><li><strong>Auto-Vectorization</strong>: Loops compile to SIMD (AVX-512/NEON).</li><li><strong>GPU Offload</strong>: <code>spawn</code> kernels directly to the GPU.</li><li><strong>Autograd</strong>: Differentiable programming syntax (<code>@{ ... }</code>) is built-in.</li></ul><h2 id="why-vex" tabindex="-1">Why Vex? <a class="header-anchor" href="#why-vex" aria-label="Permalink to &quot;Why Vex?&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Feature</th><th style="text-align:left;">Rust</th><th style="text-align:left;">Go</th><th style="text-align:left;">Python</th><th style="text-align:left;">Vex</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>GC</strong></td><td style="text-align:left;">No</td><td style="text-align:left;">Yes</td><td style="text-align:left;">Yes</td><td style="text-align:left;"><strong>No</strong></td></tr><tr><td style="text-align:left;"><strong>Safety</strong></td><td style="text-align:left;">High</td><td style="text-align:left;">Medium</td><td style="text-align:left;">Low</td><td style="text-align:left;"><strong>High</strong></td></tr><tr><td style="text-align:left;"><strong>Speed</strong></td><td style="text-align:left;">🚀🚀🚀</td><td style="text-align:left;">🚀🚀</td><td style="text-align:left;">🚀</td><td style="text-align:left;"><strong>🚀🚀🚀</strong></td></tr><tr><td style="text-align:left;"><strong>Simplicity</strong></td><td style="text-align:left;">⭐⭐</td><td style="text-align:left;">⭐⭐⭐⭐⭐</td><td style="text-align:left;">⭐⭐⭐⭐⭐</td><td style="text-align:left;"><strong>⭐⭐⭐⭐</strong></td></tr><tr><td style="text-align:left;"><strong>AI/ML</strong></td><td style="text-align:left;">Library</td><td style="text-align:left;">Library</td><td style="text-align:left;">Native-ish</td><td style="text-align:left;"><strong>Native</strong></td></tr></tbody></table><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><p>Ready to dive in?</p><ul><li><a href="./01_installation">Installation</a></li><li><a href="./03_hello_world">Hello World</a></li></ul>',18)])])}const f=e(l,[["render",n]]);export{u as __pageData,f as default};
